import { useMemo } from 'react';

import {
  getRenderingAppProps,
  getRenderingAssets,
  getRenderingFlags,
  getRenderingFramework,
  getRenderingMainEntry,
} from '@nordic/rendering-context';
import { freezeObject } from '@nordic/utils/freeze';
import {
  isExternalUrl,
  isStorybook,
  isTestEnv,
} from '@nordic/utils/validation';

import { NordicAssetNotFoundError } from './errors/asset-error';
import { NordicContextError } from './errors/context';

/**
 * Returns the props of the current page, defined in the `getServerSideProps()` function.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-context#usepageprops | Documentation}
 *
 * @example
 *
 * import { usePageProps } from 'nordic/context';
 *
 * const FooComponent = () => {
 *  const { foo } = usePageProps();
 *
 *  return (
 *    <h1>
 *      Foo value: {foo}
 *    </h1>
 *  );
 * };
 */
export function usePageProps<
  T extends Record<string, unknown> = Record<string, unknown>,
>() {
  const flags = getRenderingFlags();

  if (
    __DEV__ &&
    !isTestEnv() &&
    !isStorybook() &&
    !flags.staticMarkup &&
    !flags.stream &&
    !getRenderingMainEntry()
  ) {
    throw new NordicContextError(
      '`usePageProps()` requires the `layout.mainEntry` option. Check the render options.',
    );
  }

  return (getRenderingAppProps()?.pageProps || {}) as T;
}

/**
 * Provides access to the configured assets with prefix.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-context#useassetsprefix | Documentation}
 *
 * @example
 *
 * import { useAssetsPrefix } from 'nordic/context';
 *
 * const SomeComponent = () => {
 *  const assetsPrefix = useAssetsPrefix();
 *
 *  return (
 *    <h1>
 *      Asset with prefix: {assetsPrefix.join('some-asset.png')}
 *    </h1>
 *  );
 * };
 */
export function useAssetsPrefix() {
  return useMemo(() => {
    const assets = getRenderingAssets();

    return freezeObject({
      value: assets.prefix,
      join: (assetName: string) => {
        if (isExternalUrl(assetName)) {
          return assetName;
        }

        const fileName = assets.manifest.get(assetName);
        const fileNameWithPrefix = assets.prefix + (fileName || assetName);

        if (!__DEV__) {
          return fileNameWithPrefix;
        }

        // isTestEnv()` is only for development code, to allow unit tests execution without app build
        if (
          !fileName &&
          !isTestEnv() &&
          !isStorybook() &&
          getRenderingFramework() === 'nordic'
        ) {
          throw new NordicAssetNotFoundError(assetName);
        }

        return fileNameWithPrefix;
      },
    });
  }, []);
}
